- if:
    condition:
      wifi.connected:
    then:
      - http_request.get:
          url: "${api_commands_url}"
          request_headers:
            x-api-key: "${api_key}"
          on_response:
            then:
              - lambda: |-
                  if (response->status_code != 200 || body.length() < 3) return;

                  // Parse JSON array: [{id, endpoint, value}, ...]
                  DynamicJsonDocument doc(2048);
                  deserializeJson(doc, body);
                  JsonArray arr = doc.as<JsonArray>();

                  for (JsonObject cmd : arr) {
                    int cmd_id = cmd["id"];
                    const char* endpoint = cmd["endpoint"];
                    float value = cmd["value"].as<float>();

                    ESP_LOGI("cmd", "Executing command %d: %s = %.1f", cmd_id, endpoint, value);

                    // Map endpoint names to ESPHome number components
                    std::string ep(endpoint);
                    esphome::number::Number* target = nullptr;

                    if (ep == "target_humidity") target = id(target_humidity);
                    else if (ep == "humidifier__speed") target = id(humidifier_speed);
                    else if (ep == "humidity_hysteresis") target = id(humidity_hysteresis);
                    else if (ep == "temperature_target") target = id(temperature_target);
                    else if (ep == "temperature_hysteresis") target = id(temperature_hysteresis);
                    else if (ep == "temperature_warning_minimum") target = id(temperature_warning_minimum);
                    else if (ep == "temperature_warning_maximum") target = id(temperature_warning_maximum);
                    else if (ep == "air_exchange__period__min_") target = id(air_exchange_period_min);
                    else if (ep == "air_exchange__run_duration__s_") target = id(air_exchange_run_sec);
                    else if (ep == "air_exchange__speed") target = id(air_exchange_speed);
                    else if (ep == "lights__sunrise_hour") target = id(sunrise_hour);
                    else if (ep == "lights__duration__hours_") target = id(light_hours);
                    else if (ep == "white_led_intensity") target = id(white_intensity);
                    else if (ep == "red_led_intensity") target = id(color_r);
                    else if (ep == "green_led_intensity") target = id(color_g);
                    else if (ep == "blue_led_intensity") target = id(color_b);

                    bool success = false;
                    if (target != nullptr) {
                      auto call = target->make_call();
                      call.set_value(value);
                      call.perform();
                      success = true;
                      ESP_LOGI("cmd", "Command %d applied: %s = %.1f", cmd_id, endpoint, value);
                    } else {
                      ESP_LOGW("cmd", "Unknown endpoint: %s", endpoint);
                    }

                    // Ack the command
                    char ack_url[256];
                    snprintf(ack_url, sizeof(ack_url), "${api_ack_url}/%d/ack", cmd_id);

