# Include text sensors early so scripts can reference them
<<: !include components/text_sensors.yaml
<<: !include components/texts.yaml

# Scripts will be loaded after components to ensure all IDs are available

interval:
  # Post sensor data to remote API every 60 seconds
  - interval: 60s
    then:
      - if:
          condition:
            wifi.connected:
          then:
            - http_request.post:
                url: "${api_url}"
                request_headers:
                  Content-Type: "application/json"
                  x-api-key: "${api_key}"
                json: |-
                  root["temperature"] = id(temperature).state;
                  root["humidity"] = id(humidity).state;
