# Scripts will be loaded after components to ensure all IDs are available

interval:
  # Post sensor data to remote API every 60 seconds
  - interval: 60s
    then:
      - if:
          condition:
            wifi.connected:
          then:
            - http_request.post:
                url: "${api_url}"
                request_headers:
                  Content-Type: "application/json"
                  x-api-key: "${api_key}"
                json: |-
                  root["temperature"] = id(temperature).state;
                  root["humidity"] = id(humidity).state;
                  root["water_level"] = id(water_level_percent).state;
                  root["fan_rpm"] = id(fan_tach_internal).state;
                on_response:
                  then:
                    - lambda: |-
                        if (response->status_code == 201) {
                          ESP_LOGI("api", "Sensor data posted successfully");
                        } else {
                          ESP_LOGW("api", "API post failed with status %d", response->status_code);
                        }

  # Poll for remote commands every 30 seconds
  - interval: 30s
    then:
      - if:
          condition:
            wifi.connected:
          then:
            - http_request.get:
                url: "${api_commands_url}"
                request_headers:
                  x-api-key: "${api_key}"
                on_response:
                  then:
                    - lambda: |-
                        if (response->status_code != 200 || body.length() < 10) return;

                        // Parse single command: {id, endpoint, value}
                        int cmd_id = 0;
                        std::string endpoint_str;
                        float value = 0;

                        json::parse_json(body, [&cmd_id, &endpoint_str, &value](JsonObject root) -> bool {
                          cmd_id = root["id"] | 0;
                          const char* ep = root["endpoint"] | "";
                          const char* val = root["value"] | "0";
                          endpoint_str = std::string(ep);
                          value = atof(val);
                          return true;
                        });

                        if (cmd_id == 0 || endpoint_str.empty()) return;

                        ESP_LOGI("cmd", "Command %d: %s = %.1f", cmd_id, endpoint_str.c_str(), value);

                        esphome::number::Number* target = nullptr;

                        if (endpoint_str == "target_humidity") target = id(target_humidity);
                        else if (endpoint_str == "humidifier__speed") target = id(humidifier_speed);
                        else if (endpoint_str == "humidity_hysteresis") target = id(humidity_hysteresis);
                        else if (endpoint_str == "temperature_target") target = id(temperature_target);
                        else if (endpoint_str == "temperature_hysteresis") target = id(temperature_hysteresis);
                        else if (endpoint_str == "temperature_warning_minimum") target = id(temperature_warning_minimum);
                        else if (endpoint_str == "temperature_warning_maximum") target = id(temperature_warning_maximum);
                        else if (endpoint_str == "air_exchange__period__min_") target = id(air_exchange_period_min);
                        else if (endpoint_str == "air_exchange__run_duration__s_") target = id(air_exchange_run_sec);
                        else if (endpoint_str == "air_exchange__speed") target = id(air_exchange_speed);
                        else if (endpoint_str == "lights__sunrise_hour") target = id(sunrise_hour);
                        else if (endpoint_str == "lights__duration__hours_") target = id(light_hours);
                        else if (endpoint_str == "white_led_intensity") target = id(white_intensity);
                        else if (endpoint_str == "red_led_intensity") target = id(color_r);
                        else if (endpoint_str == "green_led_intensity") target = id(color_g);
                        else if (endpoint_str == "blue_led_intensity") target = id(color_b);

                        if (target != nullptr) {
                          auto call = target->make_call();
                          call.set_value(value);
                          call.perform();
                          ESP_LOGI("cmd", "Applied: %s = %.1f", endpoint_str.c_str(), value);
                        } else {
                          ESP_LOGW("cmd", "Unknown: %s", endpoint_str.c_str());
                        }

  # Water level check interval (every 30 seconds)
  - interval: 1s
    then:
      - script.execute: lighting_control_manager

  - interval: 60s
    then:
      - lambda: |-
          auto t = id(sntp_time).now();
          if (t.is_valid()) {
            ESP_LOGI("time",
              "Local time: %04d-%02d-%02d %02d:%02d:%02d",
              t.year, t.month, t.day_of_month,
              t.hour, t.minute, t.second
            );
          } else {
            ESP_LOGW("time", "SNTP time not valid yet");
          }


  - interval: 30s # Every 30 seconds, run the water level calculator
    then:
      - script.execute: water_level_calculator          

  # Watchdog: nudge SoftAP/DHCP if the STA link stays down
  - interval: 45s
    then:
      - lambda: |-
          const uint32_t now = millis();

          if (WiFi.isConnected()) {
            return;
          }

          if (id(ap_restart_in_progress)) {
            ESP_LOGD("wifi", "AP restart in progress; watchdog skipping.");
            return;
          }

          IPAddress ap_ip = WiFi.softAPIP();
          const uint32_t elapsed = now - id(ap_last_restart_ms);
          const bool ip_expected = (ap_ip[0] == 192 && ap_ip[1] == 168 && ap_ip[2] == 4 && ap_ip[3] == 1);

          if (ip_expected) {
            return;
          }

          if (elapsed < 30000) {
            ESP_LOGI(
              "wifi",
              "SoftAP IP %u.%u.%u.%u seen %ums after last restart; waiting before retry.",
              static_cast<unsigned int>(ap_ip[0]),
              static_cast<unsigned int>(ap_ip[1]),
              static_cast<unsigned int>(ap_ip[2]),
              static_cast<unsigned int>(ap_ip[3]),
              static_cast<unsigned int>(elapsed)
            );
            return;
          }

          ESP_LOGW(
            "wifi",
            "SoftAP IP unhealthy (%u.%u.%u.%u); re-running restart helper.",
            static_cast<unsigned int>(ap_ip[0]),
            static_cast<unsigned int>(ap_ip[1]),
            static_cast<unsigned int>(ap_ip[2]),
            static_cast<unsigned int>(ap_ip[3])
          );

          id(wifi_ap_bounce).execute();

  # Update LVGL labels every 10 seconds
  - interval: 10s
    then:
      # Update main screen value labels
      - lvgl.label.update:
          id: main_temp_value
          text: !lambda |-
            if (id(temperature).has_state()) {
              char str[20];
              sprintf(str, "%.1f°C", id(temperature).state);
              return std::string(str);
            }
            return std::string("--.-°C");

      - lvgl.label.update:
          id: main_humidity_value
          text: !lambda |-
            if (id(humidity).has_state()) {
              char str[20];
              sprintf(str, "%.1f%%", id(humidity).state);
              return std::string(str);
            }
            return std::string("--.-%");

      - lvgl.label.update:
          id: main_water_value
          text: !lambda |-
            if (id(water_level_percent).has_state()) {
              char str[20];
              sprintf(str, "%.0f%%", id(water_level_percent).state);
              return std::string(str);
            }
            return std::string("---%");

      - lvgl.label.update:
          id: main_fan_value
          text: !lambda |-
            if (id(air_exchange_on_flag)) {
              return std::string("ON");
            } else {
              return std::string("OFF");
            }

      - lvgl.label.update:
          id: main_light_value
          text: !lambda |-
            if (id(lights_on_flag)) {
              char str[20];
              sprintf(str, "%.0f lux", id(white_intensity).state);
              return std::string(str);
            } else {
              return std::string("OFF");
            }

      - lvgl.label.update:
          id: main_wifi_value
          text: !lambda |-
            if (id(ap_restart_in_progress)) {
              return std::string("Restarting AP...");
            }

            if (WiFi.isConnected()) {
              return std::string("Connected");
            }

            return std::string("AP Mode");

      - lvgl.label.update:
          id: main_ip_value
          text: !lambda |-
            if (id(ap_restart_in_progress)) {
              return std::string("--.--.--.--");
            }

            if (WiFi.isConnected()) {
              return WiFi.localIP().toString().c_str();
            }

            return std::string("192.168.4.1");

      - lvgl.label.update:
          id: main_time_label
          text: !lambda |-
            auto time = id(sntp_time).now();
            if (time.is_valid()) {
              char str[10];
              sprintf(str, "%02d:%02d", time.hour, time.minute);
              return std::string(str);
            }
            return std::string("00:00");

      - lvgl.label.update:
          id: main_uptime_value
          text: !lambda |-
            uint32_t uptime_sec = millis() / 1000;
            uint32_t hours = uptime_sec / 3600;
            uint32_t minutes = (uptime_sec % 3600) / 60;
            char str[20];
            sprintf(str, "%dh %dm", hours, minutes);
            return std::string(str);

      - lvgl.label.update:
          id: main_status_message
          text: !lambda |-
            return id(ap_status_text).c_str();

      # Force display update
      - component.update: my_display


