          id: main_light_value
          text: !lambda |-
            if (id(lights_on_flag)) {
              char str[20];
              sprintf(str, "%.0f lux", id(white_intensity).state);
              return std::string(str);
            } else {
              return std::string("OFF");
            }

      - lvgl.label.update:
          id: main_wifi_value
          text: !lambda |-
            if (id(ap_restart_in_progress)) {
              return std::string("Restarting AP...");
            }

            if (WiFi.isConnected()) {
              return std::string("Connected");
            }

            return std::string("AP Mode");

      - lvgl.label.update:
          id: main_ip_value
          text: !lambda |-
