                    - lambda: |-
                        std::string body_str = id(http_request_data).get_string();
                        ESP_LOGI("cmd", "Response %d, body: %s", response->status_code, body_str.c_str());
                        if (response->status_code != 200 || body_str.length() < 10) return;

